"""Tests for curated benchmark asset pool."""

from __future__ import annotations

from pathlib import Path
from uuid import UUID

from tests.benchmark.architectural_slides.curated_assets import (
    count_case_asset_provenance,
    ensure_case_assets,
    is_curated_asset,
    load_curated_manifest,
)


def test_curated_manifest_loads_when_present() -> None:
    manifest = load_curated_manifest()
    # Manifest is generated by scripts/materialize_benchmark_curated_assets.py
    if not manifest:
        return
    assert all(isinstance(key, str) and isinstance(value, str) for key, value in manifest.items())


def test_ensure_case_assets_prefers_curated_pool(tmp_path: Path, monkeypatch) -> None:
    asset_id = UUID("c0010001-0001-4001-8001-000000000001")
    pool_dir = tmp_path / "pool"
    pool_dir.mkdir()
    pool_file = pool_dir / f"{asset_id}.png"
    pool_file.write_bytes(b"curated-bytes")

    import tests.benchmark.architectural_slides.curated_assets as curated_mod

    monkeypatch.setattr(curated_mod, "CURATED_POOL_DIR", pool_dir)
    monkeypatch.setattr(
        curated_mod,
        "load_curated_manifest",
        lambda: {str(asset_id): f"pool/{asset_id}.png"},
    )
    monkeypatch.setattr(curated_mod, "CURATED_ROOT", tmp_path)

    case_dir = tmp_path / "case_001_site_plan" / "assets"
    paths = ensure_case_assets("case_001_site_plan", case_dir)
    assert paths
    written = case_dir / f"{asset_id}.png"
    assert written.read_bytes() == b"curated-bytes"
    total, curated, placeholder = count_case_asset_provenance(case_dir.parent)
    assert total == 1
    assert curated == 1
    assert placeholder == 0
